INSERT INTO MCP_USER_CNTR_MNG
(USERID, CNTR_MOBILE_NO, SYS_RDATE, SVC_CNTR_NO

,REP_NO


,CUSTOMER_ID

)
VALUES
(#{userid},#{mobileNo},sysdate,#{contractNo}

,#{repNo}


,#{customerId}

)

mapper.update:
UPDATE MCP_USER_CNTR_MNG
SET  SYS_UDATE = SYSDATE

        ,CNTR_MOBILE_NO = #{subscriberNo}


        ,SVC_CNTR_NO = #{contractNum}

WHERE 1=1

    AND CUSTOMER_ID = #{customerId}


    AND USERID = #{userid}


    AND SVC_CNTR_NO = #{svcCntrNo}


    AND CNTR_MOBILE_NO = #{cntrMobileNo}

 UPDATE NMCP_RETV_RSTRTN SET CONN_DATE = TO_CHAR(SYSDATE,'YYYYMMDD'), AMD_DT = SYSDATE, TMSCNT = 50
WHERE CODE = #{cd}
  AND SVC_CNTR_NO = #{ncn}

 UPDATE NMCP_RETV_RSTRTN SET TMSCNT = TMSCNT-1
WHERE CODE = #{cd}
  AND SVC_CNTR_NO = #{ncn}

INSERT INTO NMCP_CERT_HIST (
    SEQ_DATE
    , SEQ_NUM
    , CTN
    , NAME
    , ACT_DATE
    , BIRTHDAY
    , MODEL_NM
    , MODEL_SR
    , CRET_DT
    , USER_ID
    , OUTPUT_DIV_CD
) VALUES (
    TO_CHAR(SYSDATE, 'YYYYMMDD')
    , (SELECT NVL(MAX(SEQ_NUM), 0)+1 FROM NMCP_CERT_HIST WHERE SEQ_DATE = TO_CHAR(SYSDATE, 'YYYYMMDD'))
    , #{ctn}
    , #{name}
    , #{actDate}
    , #{birthday}
    , #{modelNm}
    , #{modelSr}
    , SYSDATE
    , #{userId}
    , #{outputDivCd}
)

mapper.insert:
INSERT INTO /*Mypage.insertMcpRequestArm 재약정 정보 저장  */
 MCP_REQUEST_AGRM (
      CONTRACT_NUM             --계약번호
    , SEQ                      --일련번호
    , GLOBAL_NO                --mplatform 연동 globalNo
    , DLVRY_NAME               --배송정보_이름
    , DLVRY_MOBILE_FN          --배송정보_휴대폰번호_앞자리
    , DLVRY_MOBILE_MN          --배송정보_휴대폰번호_중간자리
    , DLVRY_MOBILE_RN          --배송정보_휴대폰번호_뒷자리
    , DLVRY_POST               --배송정보_우편번호
    , DLVRY_ADDR               --배송정보_주소
    , DLVRY_ADDR_DTL           --배송정보_상세주소
    , PRESENT_CODE             --사은품 상품 코드_공통코드_presentCode
    , REGST_DTTM               --등록일
    , RVISN_DTTM               --수정일
    , ORDER_TYPE				-- 진입방법
) VALUES (
      #{contractNum}
    , NVL((SELECT MAX(SEQ+1) FROM MCP_REQUEST_AGRM WHERE CONTRACT_NUM = #{contractNum}), 1 )
    , #{globalNo}
    , #{dlvryName}
    , #{dlvryMobileFn}
    , #{dlvryMobileMn}
    , #{dlvryMobileRn}
    , #{dlvryPost}
    , #{dlvryAddr}
    , #{dlvryAddrDtl}
    , #{presentCode}
    , SYSDATE
    , SYSDATE
    , #{orderType}
)

