INSERT INTO NMCP_BILLCHRG_RESEND
    (
    SEQ
    , GLOBAL_NO
    , CONTRACT_NUM
    , MOBILE_NO
    , USER_ID
    , USER_NM
    , SUB_LINK_NM
    , GENDER
    , AGE
    , LST_COM_ACTV_DATE
    , OPEN_AGNT_CD
    , ON_OFF_TYPE
    , ORG_ID
    , BILL_TYPE_CD
    , BILL_AD_INFO
    , SUCCESS_YN
    , ERR_MSG
    , RDATE
    , RDT
    )
VALUES
    (
    NMCP_BILLCHRG_RESEND_SEQ.NEXTVAL
    , #{globalNo}
    , #{contractNum}
    , #{mobileNo}
    , #{userId}
    , #{userNm}
    , #{subLinkNm}
    , #{gender}
    , #{age}
    , #{lstComActvDate}
    , #{openAgntCd}
    , #{onOffType}
    , #{orgId}
    , #{billTypeCd}
    , #{billAdInfo}
    , #{successYn}
    , #{errMsg}
    , TO_CHAR(SYSDATE ,'YYYYMMDD')
    , SYSDATE
)

