SELECT STRT_DTTM FROM (
    SELECT STRT_DTTM FROM MCP_MRKT_HIST
    WHERE 1=1

        AND USERID = #{userid}


        AND END_DTTM = #{endDttm}


        AND AGR_YN = #{agrYn}


        AND GUBUN =  #{gubun}

    ORDER BY STRT_DTTM DESC
)
WHERE ROWNUM =1

